-- Estimate share snapshots: real backend for the V2 share flow.
--
-- Background:
--   The frontend has had an in-memory share workflow since EstimateV2 launched.
--   `/share/estimate/:shareToken` was always served from the local browser
--   store, which means anon visitors and other browsers never saw the version.
--   The two share RPCs reserved on 2026-03-06
--     - public.get_shared_estimate_version(p_share_token text)
--     - public.approve_estimate_version_by_share_token(p_share_token text, p_payload jsonb)
--   were stubbed with `raise exception 'estimate sharing is not yet implemented'`.
--
-- This migration lands the real backend:
--   * `public.estimate_share_snapshots` holds one row per share_token,
--     persisting the full V2 snapshot as jsonb plus the approval lifecycle.
--   * `public.publish_estimate_share_snapshot(...)` is the write path used by
--     the project owner / co-owner when they submit a version to share.
--   * `public.get_shared_estimate_version(...)` (re-created) becomes the
--     anon-callable read RPC behind /share/estimate/:shareToken.
--   * `public.approve_estimate_version_by_share_token(...)` (re-created)
--     applies a client's approval stamp.
--
-- Security model:
--   The table has RLS enabled with no policies, so direct table access is
--   denied to anon and authenticated. All three RPCs are SECURITY DEFINER
--   with explicit `set search_path = public` so they can read / write
--   regardless of RLS. Anon may execute the two read-oriented RPCs; only
--   authenticated owners or co-owners may execute the publish RPC.
--
-- This intentionally does NOT replace the existing in-memory share store
-- inside `rovno`. The frontend will call `publish_estimate_share_snapshot`
-- in addition to its existing local-store mutation, so the new persisted
-- copy is the canonical source for cross-browser / incognito visitors.

-- =====================================================================
-- 1. Table
-- =====================================================================

create table public.estimate_share_snapshots (
  share_token text primary key,
  project_id uuid not null references public.projects(id) on delete cascade,
  version_number integer not null check (version_number >= 1),
  status text not null default 'proposed' check (status in ('proposed', 'approved')),
  share_approval_policy text not null default 'registered'
    check (share_approval_policy in ('registered', 'disabled')),
  share_approval_disabled_reason text null
    check (
      share_approval_disabled_reason is null
      or share_approval_disabled_reason = 'no_participant_slot'
    ),
  snapshot jsonb not null,
  approval_stamp jsonb null,
  submitted boolean not null default true,
  archived boolean not null default false,
  created_by uuid not null references public.profiles(id) on delete restrict,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

-- Persisted snapshots of estimate v2 versions that have been shared via
-- /share/estimate/:shareToken. Direct access is blocked by RLS; all reads
-- and writes flow through the SECURITY DEFINER RPCs in this migration.

create index estimate_share_snapshots_project_id_idx
  on public.estimate_share_snapshots (project_id);

create index estimate_share_snapshots_active_project_idx
  on public.estimate_share_snapshots (project_id, version_number desc)
  where archived = false and submitted = true;

create trigger estimate_share_snapshots_set_updated_at
before update on public.estimate_share_snapshots
for each row execute function public.set_updated_at();

alter table public.estimate_share_snapshots enable row level security;
-- Intentionally no policies. All access is mediated by SECURITY DEFINER RPCs.

-- =====================================================================
-- 2. Replace stubbed get_shared_estimate_version
-- =====================================================================

-- The original stub returned `public.estimate_versions`. Switching the return
-- type requires a drop + create, which is safe because nothing in production
-- has ever depended on the stub returning a row.
drop function if exists public.get_shared_estimate_version(text);

create function public.get_shared_estimate_version(p_share_token text)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_row record;
begin
  if p_share_token is null or length(p_share_token) = 0 then
    return null;
  end if;

  select s.share_token,
         s.project_id,
         s.version_number,
         s.status,
         s.share_approval_policy,
         s.share_approval_disabled_reason,
         s.snapshot,
         s.approval_stamp,
         s.submitted,
         s.archived,
         s.created_by,
         s.created_at,
         s.updated_at
    into v_row
  from public.estimate_share_snapshots s
  where s.share_token = p_share_token
    and s.archived = false
    and s.submitted = true
  limit 1;

  if not found then
    return null;
  end if;

  return to_jsonb(v_row);
end;
$$;

-- Public read RPC behind /share/estimate/:shareToken. Returns jsonb with the
-- persisted snapshot and approval status, or null when the token is unknown,
-- archived, or unsubmitted.

revoke all on function public.get_shared_estimate_version(text) from public;
grant execute on function public.get_shared_estimate_version(text) to anon;
grant execute on function public.get_shared_estimate_version(text) to authenticated;

-- =====================================================================
-- 3. Replace stubbed approve_estimate_version_by_share_token
-- =====================================================================

drop function if exists public.approve_estimate_version_by_share_token(text, jsonb);

create function public.approve_estimate_version_by_share_token(
  p_share_token text,
  p_payload jsonb
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_row record;
  v_name text := nullif(trim(coalesce(p_payload->>'name', '')), '');
  v_surname text := nullif(trim(coalesce(p_payload->>'surname', '')), '');
  v_email text := nullif(trim(coalesce(p_payload->>'email', '')), '');
  v_timestamp_text text := p_payload->>'timestamp';
  v_timestamp timestamptz;
begin
  if p_share_token is null or length(p_share_token) = 0 then
    raise exception 'share token is required' using errcode = '22023';
  end if;
  if v_name is null or v_surname is null or v_email is null then
    raise exception 'approval payload must include non-empty name, surname, and email'
      using errcode = '22023';
  end if;

  begin
    v_timestamp := coalesce(v_timestamp_text::timestamptz, now());
  exception when others then
    v_timestamp := now();
  end;

  update public.estimate_share_snapshots
  set approval_stamp = jsonb_build_object(
        'name', v_name,
        'surname', v_surname,
        'email', v_email,
        'timestamp', to_char(v_timestamp at time zone 'UTC', 'YYYY-MM-DD"T"HH24:MI:SS.MS"Z"')
      ),
      status = 'approved',
      updated_at = now()
  where share_token = p_share_token
    and submitted = true
    and archived = false
    and share_approval_policy <> 'disabled'
  returning share_token,
            project_id,
            version_number,
            status,
            share_approval_policy,
            share_approval_disabled_reason,
            snapshot,
            approval_stamp,
            submitted,
            archived,
            created_by,
            created_at,
            updated_at
  into v_row;

  if not found then
    raise exception 'share token not found, archived, or approval is disabled'
      using errcode = 'P0002';
  end if;

  return to_jsonb(v_row);
end;
$$;

-- Applies a client approval stamp ({name, surname, email, timestamp}) to a
-- shared estimate version. Callable by anon (clients open the share link
-- without auth).

revoke all on function public.approve_estimate_version_by_share_token(text, jsonb) from public;
grant execute on function public.approve_estimate_version_by_share_token(text, jsonb) to anon;
grant execute on function public.approve_estimate_version_by_share_token(text, jsonb) to authenticated;

-- =====================================================================
-- 4. New publish RPC for project owners / co-owners
-- =====================================================================

create function public.publish_estimate_share_snapshot(
  p_project_id uuid,
  p_share_token text,
  p_version_number integer,
  p_snapshot jsonb,
  p_share_approval_policy text default 'registered',
  p_share_approval_disabled_reason text default null
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_caller uuid := auth.uid();
  v_row record;
begin
  if v_caller is null then
    raise exception 'authentication required to publish a share snapshot'
      using errcode = '42501';
  end if;
  if p_project_id is null then
    raise exception 'project_id is required' using errcode = '22023';
  end if;
  if p_share_token is null or length(p_share_token) = 0 then
    raise exception 'share_token is required' using errcode = '22023';
  end if;
  if p_version_number is null or p_version_number < 1 then
    raise exception 'version_number must be a positive integer' using errcode = '22023';
  end if;
  if p_snapshot is null then
    raise exception 'snapshot is required' using errcode = '22023';
  end if;
  if p_share_approval_policy is not null
     and p_share_approval_policy not in ('registered', 'disabled') then
    raise exception 'share_approval_policy must be either registered or disabled'
      using errcode = '22023';
  end if;

  -- Only owners or co-owners of the project may publish.
  if not exists (
    select 1 from public.project_members pm
    where pm.project_id = p_project_id
      and pm.profile_id = v_caller
      and pm.role in ('owner', 'co_owner')
  ) then
    raise exception 'only project owners or co-owners can publish a share snapshot'
      using errcode = '42501';
  end if;

  insert into public.estimate_share_snapshots as ess (
    share_token,
    project_id,
    version_number,
    status,
    share_approval_policy,
    share_approval_disabled_reason,
    snapshot,
    submitted,
    archived,
    created_by,
    updated_at
  ) values (
    p_share_token,
    p_project_id,
    p_version_number,
    'proposed',
    coalesce(p_share_approval_policy, 'registered'),
    p_share_approval_disabled_reason,
    p_snapshot,
    true,
    false,
    v_caller,
    now()
  )
  on conflict (share_token) do update set
    project_id = excluded.project_id,
    version_number = excluded.version_number,
    -- Re-publishing resets the approval lifecycle so the client sees fresh data.
    status = 'proposed',
    share_approval_policy = excluded.share_approval_policy,
    share_approval_disabled_reason = excluded.share_approval_disabled_reason,
    snapshot = excluded.snapshot,
    approval_stamp = null,
    submitted = true,
    archived = false,
    updated_at = now()
  returning share_token,
            project_id,
            version_number,
            status,
            share_approval_policy,
            share_approval_disabled_reason,
            snapshot,
            approval_stamp,
            submitted,
            archived,
            created_by,
            created_at,
            updated_at
  into v_row;

  return to_jsonb(v_row);
end;
$$;

-- Owners / co-owners write path for the estimate share. Inserts or upserts
-- the snapshot under the provided share_token. Re-publishing resets approval
-- state back to proposed.

revoke all on function public.publish_estimate_share_snapshot(uuid, text, integer, jsonb, text, text) from public;
grant execute on function public.publish_estimate_share_snapshot(uuid, text, integer, jsonb, text, text) to authenticated;
